import re
import boto3


def validate_endpoint(url: str) -> bool:
    """Validate that the provided URL is a legitimate HTTPS endpoint."""
    # Only allow HTTPS protocol
    if not url.startswith("https://"):
        print("Error: Only HTTPS endpoints are allowed.")
        return False

    # Basic URL format validation
    url_pattern = re.compile(
        r'^https://'
        r'(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?\.)+' 
        r'[a-zA-Z]{2,}'
        r'(?::\d{1,5})?'
        r'(?:/[^\s]*)?$'
    )
    if not url_pattern.match(url):
        print("Error: Invalid URL format.")
        return False

    # Block internal/private network endpoints to prevent SSRF
    blocked_patterns = [
        r'https?://localhost',
        r'https?://127\.',
        r'https?://10\.',
        r'https?://172\.(1[6-9]|2[0-9]|3[01])\.',
        r'https?://192\.168\.',
        r'https?://169\.254\.',  # AWS metadata endpoint
        r'https?://\[',         # IPv6 addresses
        r'https?://0\.',
        r'https?://metadata',
        r'https?://internal',
    ]
    for pattern in blocked_patterns:
        if re.match(pattern, url, re.IGNORECASE):
            print("Error: Internal/private network endpoints are not allowed.")
            return False

    # Limit URL length
    if len(url) > 2048:
        print("Error: URL exceeds maximum length of 2048 characters.")
        return False

    return True


def validate_topic_arn(topic_arn: str) -> bool:
    """Validate that the topic ARN matches expected SNS ARN format."""
    arn_pattern = re.compile(
        r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$'
    )
    if not arn_pattern.match(topic_arn):
        print("Error: Invalid SNS Topic ARN format.")
        return False
    return True


def get_allowed_topic_arns() -> list:
    """Return a list of allowed topic ARNs (allowlist approach)."""
    # In production, load this from a config file or environment variable
    import os
    allowed = os.environ.get("ALLOWED_SNS_TOPIC_ARNS", "")
    if allowed:
        return [arn.strip() for arn in allowed.split(",") if arn.strip()]
    return []


def create_subscription(topic_arn: str, endpoint_url: str) -> dict | None:
    """Create an SNS subscription with validated inputs."""
    # Validate topic ARN format
    if not validate_topic_arn(topic_arn):
        return None

    # Check topic ARN against allowlist
    allowed_topics = get_allowed_topic_arns()
    if allowed_topics and topic_arn not in allowed_topics:
        print(f"Error: Topic ARN is not in the allowed list.")
        return None

    # Validate endpoint URL
    if not validate_endpoint(endpoint_url):
        return None

    try:
        sns_client = boto3.client("sns")

        # Verify the topic exists before subscribing
        try:
            sns_client.get_topic_attributes(TopicArn=topic_arn)
        except sns_client.exceptions.NotFoundException:
            print("Error: SNS topic does not exist.")
            return None

        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol="https",
            Endpoint=endpoint_url,
            ReturnSubscriptionArn=True,
        )

        print(f"Subscription created successfully.")
        print(f"Subscription ARN: {response.get('SubscriptionArn')}")
        return response

    except sns_client.exceptions.AuthorizationErrorException:
        print("Error: Not authorized to subscribe to this topic.")
        return None
    except Exception as e:
        print(f"Error creating subscription: {e}")
        return None


def main():
    print("=== SNS Subscription Manager ===")
    print()

    topic_arn = input("Enter SNS Topic ARN: ").strip()
    endpoint_url = input("Enter HTTPS webhook endpoint URL: ").strip()

    if not topic_arn or not endpoint_url:
        print("Error: Both Topic ARN and endpoint URL are required.")
        return

    # Confirm with user before creating
    print(f"\nAbout to create subscription:")
    print(f"  Topic: {topic_arn}")
    print(f"  Endpoint: {endpoint_url}")
    print(f"  Protocol: https")

    confirmation = input("\nProceed? (yes/no): ").strip().lower()
    if confirmation != "yes":
        print("Subscription cancelled.")
        return

    create_subscription(topic_arn, endpoint_url)


if __name__ == "__main__":
    main()